### Logging/Tracing Requirements

```rust
use tracing::{debug, info, warn, error, instrument};

impl FilesystemProvider {
    #[instrument(level = "info", skip(self))]
    pub fn list_resources(&self) -> Result<Vec<Resource>, ResourceError> {
        info!(
            root = %self.root.display(),
            recursive = self.recursive,
            "Listing filesystem resources"
        );

        let mut resources = Vec::new();
        self.walk_directory(&self.root, &mut resources)?;

        info!(count = resources.len(), "Filesystem listing complete");
        resources
    }

    #[instrument(level = "debug", skip(self), fields(root = %self.root.display()))]
    pub fn read_resource(&self, uri: &str) -> Result<ReadResourceResult, ResourceError> {
        debug!(uri = %uri, "Reading filesystem resource");

        // Validate path
        let path = self.validate_path(uri).map_err(|e| {
            warn!(uri = %uri, error = %e, "Path validation failed");
            e
        })?;

        // Check file size
        let metadata = std::fs::metadata(&path)?;
        if metadata.len() > self.max_file_size as u64 {
            warn!(
                path = %path.display(),
                size = metadata.len(),
                max = self.max_file_size,
                "File exceeds maximum size"
            );
            return Err(ResourceError::TooLarge {
                path: path.display().to_string(),
                size: metadata.len(),
                max: self.max_file_size,
            });
        }

        // Read content
        let content = std::fs::read_to_string(&path)?;
        let mime_type = detect_mime_type(&path);

        debug!(
            path = %path.display(),
            size = content.len(),
            mime_type = %mime_type,
            "File read successfully"
        );

        Ok(ReadResourceResult {
            contents: vec![ResourceContent::text(content).with_mime_type(mime_type)],
        })
    }
}
```

